128:     // inline definitions
129: 
130:     inline void Instrument::calculate() const {
131:         if (!calculated_) {
132:             if (isExpired()) {
133:                 setupExpired();
134:                 calculated_ = true;
135:             } else {
136:                 LazyObject::calculate();
137:             }
138:         }
139:     }
140: 
141:     inline void Instrument::setupExpired() const {
142:         NPV_ = errorEstimate_ = 0.0;
143:         valuationDate_ = Date();
144:         additionalResults_.clear();
145:     }
146: 
147:     inline void Instrument::performCalculations() const {
148:         QL_REQUIRE(engine_, "null pricing engine");
149:         engine_->reset();
150:         setupArguments(engine_->getArguments());
151:         engine_->getArguments()->validate();
152:         engine_->calculate();
153:         fetchResults(engine_->getResults());
154:     }
155: 
156:     inline void Instrument::fetchResults(
157:                                       const PricingEngine::results* r) const {
158:         const auto* results = dynamic_cast<const Instrument::results*>(r);
159:         QL_ENSURE(results != nullptr, "no results returned from pricing engine");
160: 
161:         NPV_ = results->value;
162:         errorEstimate_ = results->errorEstimate;
163:         valuationDate_ = results->valuationDate;
164: 
165:         additionalResults_ = results->additionalResults;
166:     }
